#include <stdio.h>

int main() {
    int t;
    scanf("%d", &t);  // Number of test cases

    while (t--) {
        int n;
        scanf("%d", &n);  // Length of the array

        if (n % 4 != 0) {
            printf("NO\n");  // No suitable answer exists
        } else {
            printf("YES\n");

            int half = n / 2;
            int even = 2;  // First even number to start with
            int odd = 1;   // First odd number to start with

            // Construct the array with alternating even and odd elements
            for (int i = 0; i < half; i++) {
                printf("%d ", even);
                even += 2;
            }

            // Continue with remaining odd numbers
            for (int i = half; i < n - 1; i++) {
                printf("%d ", odd);
                odd += 2;
            }

            printf("%d\n", even + (n / 2) - 1);  // Remaining even number to satisfy the sum condition
        }
    }

    return 0;
}
```

